func solve(s string) []string {
    var segments []string
    seen := make(map[string]bool)
    start := 0
    for start < len(s) {
        current := ""
        for i := start; i < len(s); i++ {
            current += string(s[i])
            if !seen[current] {
                seen[current] = true
                segments = append(segments, current)
                start = i + 1
                break
            }
        }
    }
    return segments
}
